"""
Cấu hình Bot - Chỉnh sửa file này theo nhu cầu của bạn
"""

import os
from dotenv import load_dotenv

load_dotenv()

# Logo LEADSMAX Group (base64 nhúng thẳng vào email, không cần host file)
LOGO_BASE64 = ""


class Config:
    # ─────────────────────────────────────────────
    # 🔑 THÔNG TIN XÁC THỰC (đặt trong file .env)
    # ─────────────────────────────────────────────
    TELEGRAM_BOT_TOKEN: str = os.getenv("TELEGRAM_BOT_TOKEN", "")

    # Danh sách Telegram User ID được phép dùng bot
    ALLOWED_USER_IDS: list[int] = [
        int(x) for x in os.getenv("ALLOWED_USER_IDS", "").split(",") if x.strip()
    ]

    # ─────────────────────────────────────────────
    # 🔐 CẤU HÌNH SMTP/IMAP (Gmail App Password)
    # ─────────────────────────────────────────────
    SMTP_HOST: str = os.getenv("SMTP_HOST", "smtp.gmail.com")
    SMTP_PORT: int = int(os.getenv("SMTP_PORT", "587"))
    SMTP_USERNAME: str = os.getenv("SMTP_USERNAME", "")
    SMTP_PASSWORD: str = os.getenv("SMTP_PASSWORD", "")

    IMAP_HOST: str = os.getenv("IMAP_HOST", "imap.gmail.com")
    IMAP_PORT: int = int(os.getenv("IMAP_PORT", "993"))
    IMAP_USERNAME: str = os.getenv("IMAP_USERNAME", "")
    IMAP_PASSWORD: str = os.getenv("IMAP_PASSWORD", "")

    # ─────────────────────────────────────────────
    # 🏷️ CẤU HÌNH LABEL GMAIL
    # ─────────────────────────────────────────────
    REJECTED_LABEL: str = "rejected"
    REPLIED_LABEL: str = "replied"

    # ─────────────────────────────────────────────
    # ⚙️ CẤU HÌNH GỬI EMAIL
    # ─────────────────────────────────────────────
    REPLY_SUBJECT_PREFIX: str = "Re: "
    MAX_EMAILS_PER_SCAN: int = 200
    SEND_DELAY_SECONDS: float = 1.5

    # ─────────────────────────────────────────────
    # 📧 THÔNG TIN CÔNG TY
    # ─────────────────────────────────────────────
    SENDER_NAME: str = os.getenv("SENDER_NAME", "HR Department")
    SENDER_COMPANY: str = os.getenv("SENDER_COMPANY", "LEADSMAX Group")
    COMPANY_PHONE: str = os.getenv("COMPANY_PHONE", "(+84) 372 571 498")
    COMPANY_WEBSITE: str = os.getenv("COMPANY_WEBSITE", "https://leadsmaxgroup.com/")
    COMPANY_ADDRESS: str = os.getenv("COMPANY_ADDRESS", "84 Ho Tung Mau, Hoa Minh, Lien Chieu, Da Nang, Vietnam")

    # ─────────────────────────────────────────────
    # 📧 TEMPLATE EMAIL TỪ CHỐI (Plain Text)
    # ─────────────────────────────────────────────
    EMAIL_BODY_PLAIN: str = """Dear {name},

Thank you for your interest at {company} and for taking the time to submit your application.

After reviewing your CV, we regret to inform you that we will not be moving forward with your application at this time, as we have decided to proceed with other candidates whose qualifications more closely match our current requirements.

We truly appreciate your interest in joining our team and wish you every success in your future career.

Best regards,
{sender_name}
{company}

Human Resources
Phone:   {phone}
Website: {website}
Add:     {address}
"""

    # ─────────────────────────────────────────────
    # 📧 TEMPLATE EMAIL HTML (giống hệt ảnh mẫu)
    # ─────────────────────────────────────────────
    EMAIL_BODY_HTML: str = """<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
</head>
<body style="margin:0; padding:0; font-family: Arial, sans-serif; background-color:#ffffff;">
  <div style="max-width:640px; margin:0 auto; padding:32px 24px; color:#222222;">

    <!-- Nội dung chính -->
    <p style="margin:0 0 16px 0; font-size:14px; line-height:1.6;">Dear <strong>{name}</strong>,</p>

    <p style="margin:0 0 16px 0; font-size:14px; line-height:1.6;">
      Thank you for your interest at <strong>{company}</strong> and for taking
      the time to submit your application.
    </p>

    <p style="margin:0 0 16px 0; font-size:14px; line-height:1.6;">
      After reviewing your CV, we regret to inform you that we will
      not be moving forward with your application at this time, as we
      have decided to proceed with other candidates whose
      qualifications more closely match our current requirements.
    </p>

    <p style="margin:0 0 16px 0; font-size:14px; line-height:1.6;">
      We truly appreciate your interest in joining our team and wish
      you every success in your future career.
    </p>

    <p style="margin:0 0 4px 0; font-size:14px; line-height:1.6;">Best regards,</p>
    <p style="margin:0 0 4px 0; font-size:14px; line-height:1.6;">{sender_name}</p>
    <p style="margin:0 0 24px 0; font-size:14px; line-height:1.6;">{company}</p>

    <!-- Đường kẻ ngang -->
    <hr style="border:none; border-top:1px solid #cccccc; margin:0 0 20px 0;">

    <!-- Signature block -->
    <table cellpadding="0" cellspacing="0" border="0" width="100%">
      <tr>
        <td valign="top" style="padding-bottom: 12px;">
          <p style="margin:0 0 8px 0; font-size:16px; font-weight:bold; font-family:Arial, sans-serif; color:#222;">
            Human Resources
          </p>
        </td>
      </tr>
      <tr>
        <td valign="middle">
          <table cellpadding="0" cellspacing="0" border="0">
            <tr>
              <!-- Logo -->
              <td valign="middle" style="padding-right:20px;">
                <img
                  src="data:image/jpeg;base64,{logo_b64}"
                  alt="{company}"
                  width="120"
                  style="display:block; border:0;"
                />
              </td>
              <!-- Thông tin liên hệ -->
              <td valign="middle">
                <table cellpadding="2" cellspacing="0" border="0" style="font-family:Arial, sans-serif; font-size:13px; color:#444;">
                  <tr>
                    <td style="color:#888; padding-right:6px; white-space:nowrap;"><strong>Phone:</strong></td>
                    <td style="color:#e05c00;">{phone}</td>
                  </tr>
                  <tr>
                    <td style="color:#888; padding-right:6px; white-space:nowrap;"><strong>Website:</strong></td>
                    <td><a href="{website}" style="color:#e05c00; text-decoration:none;">{website}</a></td>
                  </tr>
                  <tr>
                    <td style="color:#888; padding-right:6px; white-space:nowrap; vertical-align:top;"><strong>Add:</strong></td>
                    <td style="color:#888;">{address}</td>
                  </tr>
                </table>
              </td>
            </tr>
          </table>
        </td>
      </tr>
    </table>

  </div>
</body>
</html>"""

    @classmethod
    def build_rejection_body(
        cls,
        recipient_name: str,
        recipient_email: str,
        original_subject: str
    ) -> dict:
        display_name = recipient_name if recipient_name else recipient_email

        vars_map = {
            "name": display_name,
            "email": recipient_email,
            "subject": original_subject,
            "company": cls.SENDER_COMPANY,
            "sender_name": cls.SENDER_NAME,
            "phone": cls.COMPANY_PHONE,
            "website": cls.COMPANY_WEBSITE,
            "address": cls.COMPANY_ADDRESS,
            "logo_b64": LOGO_BASE64,
        }

        return {
            "plain": cls.EMAIL_BODY_PLAIN.format(**vars_map),
            "html": cls.EMAIL_BODY_HTML.format(**vars_map),
        }
